#!/user/bin/env python3from .library_classes import Bookfrom importlib import resourcesimport jsonimport zipfileimport pathlibimport osimport sysimport subprocess# Декоратор для проверки исключенийdef decorator_exception_handler_with_arguments(file_not_found_text):    def decorator(func):        def wrapper(*args, **kwargs):            try:                func(*args, **kwargs)            except FileNotFoundError:                print(f"{file_not_found_text}")        return wrapper    return decorator# Функция для проверки на инициализацию книги, библиотеки и фильтра def is_initialized(dict_of_obj):    uninit = []    counter = 0    for elem in dict_of_obj.keys():        if dict_of_obj[elem]:            counter += 1        else:            uninit.append(elem)    if counter == len(list(dict_of_obj.keys())):        return True    else:        if len(uninit) == 1:            print(f"{uninit[0][0].upper()}{uninit[0][1:]} не выбран(а)")        elif len(uninit) == 2:            print(f"{uninit[0][0].upper()}{uninit[0][1:]} и {uninit[1]} не выбраны")        else:            print(f"{uninit[0][0].upper()}{uninit[0][1:]}, {uninit[1]} и {uninit[2]} не выбраны")            # Функция для стопкиdef stack_delete_book(stack, n):    stack_copy = []    if len(stack) == 0:        print("Стопка пуста")    else:        for i in range(1, len(stack)+1):            if i != n:               stack_copy.append(stack[i-1])        stack = stack_copy# Функции и переменные, ассоциированные с работой с архивомpath_to_home = str(pathlib.Path.home() / "Desktop/home_library/")dict_dec_values = {"file_not_found_text": ["Не удалось найти такой файл. Проверьте правильность названия и расширения",                                            "Архив пока не создан. Чтобы создать архив, добавьте в него в него первый файл"]}@decorator_exception_handler_with_arguments(dict_dec_values["file_not_found_text"][0])def add_to_archive(book_name: str, library_name: str, extention: str) -> None:    name_file = book_name.replace(" ", "_")    added_file_path = pathlib.Path.home() / f"Desktop/{name_file}.{extention}"    with zipfile.ZipFile(str(pathlib.Path.home() / f"Desktop/home_library/{library_name.replace(" ", "_")}_archive.zip"), "a") as archive:        archive.write(str(added_file_path), arcname=os.path.basename(str(added_file_path)))@decorator_exception_handler_with_arguments(dict_dec_values["file_not_found_text"][1])def read_from_archive(book_name: str, library_name: str) -> None:    extention = ""    file_named = ""    with zipfile.ZipFile(f"{path_to_home}/{library_name.replace(" ", "_")}_archive.zip", "r") as archive:        list_of_files = archive.namelist()        for text in list_of_files:            name, ext = os.path.splitext(text)            if name == book_name.replace(" ", "_"):                extention = ext                file_named = name                archive.extract(f"{name}{extention}", path_to_home)            else:                pass    path_to_text = f"{path_to_home}/{file_named}{extention}"    if sys.platform == "win32":        os.startfile(path_to_text)    elif sys.platform == "darwin":        subprocess.run(["open", path_to_text])    else:        subprocess.run(["xdg-open", path_to_text]) @decorator_exception_handler_with_arguments(dict_dec_values["file_not_found_text"][1])    def check_in_archive(book_name: str, library_name: str) -> None:    with zipfile.ZipFile(f"{path_to_home}/{library_name.replace(" ", "_")}_archive.zip", "r") as archive:        list_of_names = archive.namelist()        list_by_name = []        for text in list_of_names:            name, ext = os.path.splitext(text)            list_by_name.append(name)    if book_name.replace(" ", "_") in list_by_name:        print("Книга в архиве")    else:        print("Книга не добавлена в архив")# Функции и переменные, ассоциированные с изменением характеристик книгjson_path = resources.files('library_manager') / 'book_chars.json'def adding_book_chars(form: str, to_add: list, add_singular: str, add_plural: str) -> None:    change = True    with json_path.open("r", encoding="utf-8") as file:        book_chars = json.load(file)    if len(to_add) == 1:        if to_add[0] in book_chars[form]:            change = False            print(f"Такой(ая) {add_singular} уже есть")        else:            book_chars[form].append(to_add[0])    else:        same = list(set(book_chars[form]) & set(to_add))        if len(same) == 0:            book_chars[form].extend(to_add)        else:            to_add_final = [elem for elem in to_add if elem not in same]            if to_add_final:                book_chars[form].extend(to_add_final)                print(f"Уже доступные {add_plural} исключены из добавления: {same}, остальные добавлены")            else:                change = False                print(f"Все введенные {add_plural} уже доступны")    if change:        with json_path.open("w", encoding="utf-8") as file:            json.dump(book_chars, file, ensure_ascii=False)        Book.update_chars()        def deleting_book_chars(form: str, to_delete: list, delete_singular: str, delete_plural: str) -> None:    change = True    with json_path.open("r", encoding="utf-8") as file:        book_chars = json.load(file)    if len(to_delete) == 1:        if to_delete[0] not in book_chars[form]:            print(f"Такого(ой) {delete_singular} нет среди доступных")            change = False        else:            book_chars[form].remove(to_delete[0])    else:        same = list(set(book_chars[form]) & set(to_delete))        if len(same) == len(to_delete):            for el in same:                book_chars[form].remove(el)        else:            to_delete_final = [genre for genre in to_delete if genre in same]            if to_delete_final:                different = [genre for genre in to_delete if genre not in same]                for el in to_delete_final:                    book_chars[form].remove(el)                print(f"Несуществующие {delete_plural} не удалены: {different}, остальные удалены")            else:                change = False                print(f"Указанные {delete_plural} недоступны")    if change:        with json_path.open("w", encoding="utf-8") as file:            json.dump(book_chars, file, ensure_ascii=False)        Book.update_chars()        def resetting_to_default(form: str) -> None:    with json_path.open("r", encoding="utf-8") as file:        book_chars = json.load(file)    book_chars[form] = book_chars[f"{form}_OG"]    with json_path.open("w", encoding="utf-8") as file:        json.dump(book_chars, file, ensure_ascii=False)    Book.update_chars()